# Check active kill zones
import datetime

KILL_ZONES = {
    "Asian": {"start": "21:00", "end": "04:00"},
    "London Open": {"start": "02:50", "end": "04:00"},
    "London": {"start": "03:00", "end": "12:00"},
    "New York": {"start": "08:00", "end": "17:00"},
    "London Close": {"start": "10:30", "end": "11:00"}
}

def get_active_sessions():
    utc_now = datetime.datetime.now(datetime.timezone.utc)
    est_offset = -5 if (utc_now.month < 3 or utc_now.month > 11) else -4
    est_time = utc_now + datetime.timedelta(hours=est_offset)
    current = est_time.strftime("%H:%M")

    active = []
    for name, data in KILL_ZONES.items():
        start, end = data["start"], data["end"]
        if start > end:  # Overnight
            if current >= start or current <= end:
                active.append(name)
        else:
            if start <= current <= end:
                active.append(name)
    return active

active_sessions = get_active_sessions()
return {"sessions": active_sessions, "active": len(active_sessions) > 0}

